#include <bits/stdc++.h>
using namespace std;

const int mod=100003;

long long m,n;

long long quick_mi(long long a,long long b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int main(){
    scanf("%lld%lld",&m,&n);
    m%=mod;
    printf("%lld",(quick_mi(m,n)-m*quick_mi(m-1,n-1)%mod+mod)%mod);
    return 0;
}
